// // This module implements a binary counter that decrements from 15 to 0 and then wraps around to 15. It has an asynchronous reset and a clock enable signal. When the reset signal is asserted, the counter should reset to 15 regardless of the clock signal. When the clock enable signal is not asserted, the counter should hold its value.
module binary_counter
    (
        input rst_n, 
        input clk, 
        input enable,
        output reg [3:0] count
    );

    always @(posedge clk or negedge rst_n) 
    begin
        if (!rst_n)
            count <= 4'd0;
        else if (enable)
        begin
            if (count == 4'd15)
                count <= 4'd0;
            else
                count <= count + 1;
        end
    end

endmodule
